var body = $input.first().json.body || $input.first().json;
var tenantId = String(body.tenantId || '');
var documentType = String(body.documentType || '');
var documentId = String(body.documentId || '');
var etape = String(body.etape || '');
var etapePrecedente = body.etapePrecedente ? String(body.etapePrecedente) : null;
var etapeSuivante = body.etapeSuivante ? String(body.etapeSuivante) : null;
var commentaire = body.commentaire ? String(body.commentaire) : null;
var utilisateur = body.utilisateur ? String(body.utilisateur) : 'system';

var UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

if (!tenantId || !UUID_RE.test(tenantId)) {
  throw new Error('Tenant ID requis et doit être un UUID valide');
}
if (!documentId || !UUID_RE.test(documentId)) {
  throw new Error('Document ID requis et doit être un UUID valide');
}
if (!documentType) {
  throw new Error('Document Type requis (devis|commande|livraison|facture|ecriture|paiement)');
}
if (!etape) {
  throw new Error('Etape requise (CREATION|VALIDATION|ENVOI|ACCEPTATION|PAIEMENT|CLOTURE)');
}

return [{
  json: {
    tenantId: tenantId,
    documentType: documentType,
    documentId: documentId,
    etape: etape,
    etapePrecedente: etapePrecedente,
    etapeSuivante: etapeSuivante,
    commentaire: commentaire,
    utilisateur: utilisateur,
    timestamp: new Date().toISOString()
  }
}];

var crypto = require('crypto');
var parser = $('02. Parser').first().json;
var prevData = $('05. Get Previous').first().json;
var previousHash = prevData && prevData.hash_verification ? prevData.hash_verification : '';

var dataToHash = previousHash + parser.documentType + parser.documentId + parser.etape + parser.timestamp;
var hashHex = crypto.createHash('sha256').update(dataToHash).digest('hex');

return [{
  json: {
    previousHash: previousHash,
    currentHash: hashHex,
    dataToHash: dataToHash
  }
}];

var parser = $('02. Parser').first().json;
var hash = $('06. Build Hash').first().json;
var commentaire = parser.commentaire ? parser.commentaire.replace(/'/g, "''") : '';
var utilisateur = parser.utilisateur.replace(/'/g, "''");

var metadata = JSON.stringify({
  hash_chain_valid: true,
  previous_hash: hash.previousHash
}).replace(/'/g, "''");

var query = "INSERT INTO pistes_audit (id, tenant_id, document_type, document_id, etape, etape_precedente, etape_suivante, date_etape, utilisateur, commentaire, hash_verification, metadata, created_at) " +
  "VALUES (gen_random_uuid(), '" + parser.tenantId + "', '" + parser.documentType + "', '" + parser.documentId + "', '" + parser.etape + "', " +
  (parser.etapePrecedente ? "'" + parser.etapePrecedente + "'" : "NULL") + ", " +
  (parser.etapeSuivante ? "'" + parser.etapeSuivante + "'" : "NULL") + ", " +
  "'" + parser.timestamp + "', '" + utilisateur + "', '" + commentaire + "', '" + hash.currentHash + "', '" + metadata + "', NOW()) " +
  "RETURNING *";

return [{
  json: {
    query: query,
    currentHash: hash.currentHash
  }
}];

var items = $input.all();
var entry = items.map(function(item) { return item.json; }).filter(function(r) { return r && r.id; })[0];

if (!entry) {
  return [{json: {success: false, error: 'Création piste audit échouée'}}];
}

return [{json: {
  success: true,
  entry: {
    id: entry.id,
    documentType: entry.document_type,
    documentId: entry.document_id,
    etape: entry.etape,
    dateEtape: entry.date_etape,
    utilisateur: entry.utilisateur,
    hashVerification: entry.hash_verification,
    createdAt: entry.created_at
  }
}}];
